esqlQuery.esql:
TS metrics-kubeletstatsreceiver.otel-*, metrics-k8sclusterreceiver.otel-*
| WHERE k8s.node.name IS NOT NULL
    AND (k8s.node.memory.working_set IS NOT NULL OR k8s.node.allocatable_memory IS NOT NULL)
| STATS avg_memory = AVG(k8s.node.memory.working_set),
    allocatable_memory = MAX(k8s.node.allocatable_memory)
    BY k8s.node.name
| EVAL memory_utilization = avg_memory / allocatable_memory
// Alert when average memory working set exceeds 85% of allocatable.
// Adjust the threshold to suit your environment.
//
// Requires k8s.node.allocatable_memory from k8sclusterreceiver.
// This metric is controlled by allocatable_types_to_report config
// option, which must include "memory". Not enabled by default.
// If unavailable, replace the utilization check with a static
// threshold on avg_memory, e.g.: WHERE avg_memory > 13743895347
| WHERE memory_utilization > 0.85
| EVAL avg_memory_gib = ROUND(avg_memory / 1073741824, 2)
| KEEP k8s.node.name, avg_memory_gib, allocatable_memory, memory_utilization
